&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px;&quot;&gt;&amp;nbsp;&lt;/p&gt;
&lt;p style=&quot;margin-bottom: 0px; margin-top: 0px;&quot;&gt;&lt;span style=&quot;font-weight: bold;&quot;&gt;The Role&lt;/span&gt;&lt;/p&gt;
